import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure input does not exceed buffer size
        if (name.length() > 10) {
            System.out.println("Input exceeds buffer size.");
            scanner.close();
            return;
        }

        char[] buffer = new char[10];

        // Copy input into buffer
        name.getChars(0, name.length(), buffer, 0);

        // Print the content of the buffer securely
        System.out.println("Hello, " + new String(buffer).trim());

        scanner.close();
    }
}

